// 智能预处理 Telegram 消息
const messageText = $json.message.text;
const messageDate = new Date($json.message.date * 1000);

// 1. 提取数字 ID (包括带 PANDA- 前缀的)
const idPattern = /(?:PANDA-)?(\d{16,})/g;
const extractedIds = [];
let match;
while ((match = idPattern.exec(messageText)) !== null) {
  extractedIds.push(match[1]);
}

// 2. 移除 ID 和多余信息，提取自然语言查询
let cleanQuery = messageText
  .replace(/(?:PANDA-)?\d{16,}/g, '') // 移除所有 ID
  .replace(/\b[A-Za-z]+\d+\b/g, '') // 移除类似 ydb3626 的标识
  .replace(/\b(墨西哥|User\d+)\b/g, '') // 移除地区信息
  .replace(/\s+/g, ' ') // 合并多个空格
  .trim();

// 如果清理后为空，使用默认查询
if (!cleanQuery || cleanQuery.length < 3) {
  cleanQuery = "查询这些记录的游戏数据";
}

// 3. 计算时间范围 (最近一周)
const oneWeekAgo = new Date(messageDate);
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

const startTime = Math.floor(oneWeekAgo.getTime() / 1000) * 1000; // 转换为毫秒时间戳
const endTime = Math.floor(messageDate.getTime() / 1000) * 1000;

// 4. 构建增强的查询提示
let enhancedQuery = cleanQuery;

if (extractedIds.length > 0) {
  enhancedQuery += `\n\n相关记录ID: ${extractedIds.join(', ')}`;
}

enhancedQuery += `\n\n默认查询条件：\n`;
enhancedQuery += `- 提供商: gp 和 popular\n`;
enhancedQuery += `- 时间范围: 最近一周 (${oneWeekAgo.toLocaleDateString()} 到 ${messageDate.toLocaleDateString()})\n`;

if (extractedIds.length > 0) {
  enhancedQuery += `- 指定ID: ${extractedIds.join(', ')}`;
}

// 5. 返回处理后的数据
return {
  json: {
    // 原始数据
    originalMessage: messageText,
    messageDate: messageDate.toISOString(),
    chatId: $json.message.chat.id,
    messageId: $json.message.message_id,

    // 提取的数据
    extractedIds: extractedIds,
    cleanQuery: cleanQuery,
    enhancedQuery: enhancedQuery,

    // 时间范围
    startTime: startTime,
    endTime: endTime,
    startDate: oneWeekAgo.toISOString().split('T')[0],
    endDate: messageDate.toISOString().split('T')[0],

    // 默认条件
    defaultProviders: ['gp', 'popular'],

    // 查询统计
    hasSpecificIds: extractedIds.length > 0,
    hasTimeRange: true,
    hasProviderFilter: true,

    // 传递给 AI 的最终查询
    aiQuery: enhancedQuery
  }
};

